request.query:
BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?supplier ?name WHERE {
  ?pkg vocab:NamedElement_name ?pkgName .
  FILTER(CONTAINS(LCASE(STR(?pkgName)), LCASE("L3%20APT%20Requirements")))
  ?pkg vocab:Dependency_supplier ?supplier .
  OPTIONAL { ?supplier vocab:NamedElement_name ?name }
}
LIMIT 25
